const today = new Date().toISOString().split('T')[0];
const stage = ($json.stage || '').trim();
const currentNotes = ($json.status_notes || '').trim();
const currentOverview = ($json.overview_sent || 'No').trim() || 'No';
const currentBooked = ($json.booked_call || 'No').trim() || 'No';
const currentCallDate = ($json.call_date || '').trim();

function addDays(base, days) {
  const d = new Date(base + 'T00:00:00');
  d.setDate(d.getDate() + days);
  return d.toISOString().split('T')[0];
}

let nextActionDate = $json.next_action_date || '';
let lastContactDate = $json.last_contact_date || '';
let overviewSent = currentOverview;
let bookedCall = currentBooked;
let callDate = currentCallDate;
let recommendedNextStep = $json.recommended_next_step || '';
let append = '';

switch (stage) {
  case 'Connection Sent':
    lastContactDate = today;
    nextActionDate = addDays(today, 3);
    recommendedNextStep = 'Check whether connection was accepted';
    append = 'Connection request sent';
    break;
  case 'Accepted':
    nextActionDate = today;
    recommendedNextStep = 'Send first follow-up message';
    append = 'Connection accepted';
    break;
  case 'Messaged 1':
    lastContactDate = today;
    nextActionDate = addDays(today, 4);
    recommendedNextStep = 'Follow up if no reply';
    append = 'First message sent';
    break;
  case 'Replied':
    nextActionDate = today;
    recommendedNextStep = 'Review reply and respond manually';
    append = 'Lead replied';
    break;
  case 'Pain Identified':
    nextActionDate = today;
    recommendedNextStep = 'Send relevant resource or tailored message';
    append = 'Pain point identified';
    break;
  case 'Overview Requested':
    nextActionDate = today;
    recommendedNextStep = 'Send overview / demo materials';
    append = 'Overview requested';
    break;
  case 'Overview Sent':
    lastContactDate = today;
    overviewSent = 'Yes';
    nextActionDate = addDays(today, 3);
    recommendedNextStep = 'Follow up after sending overview';
    append = 'Overview sent';
    break;
  case 'Call Invited':
    lastContactDate = today;
    nextActionDate = addDays(today, 3);
    recommendedNextStep = 'Check if they booked a call';
    append = 'Call invitation sent';
    break;
  case 'Call Booked':
    bookedCall = 'Yes';
    nextActionDate = '';
    recommendedNextStep = 'Prepare for booked call';
    append = 'Call booked';
    break;
  case 'Not Now':
    nextActionDate = addDays(today, 45);
    recommendedNextStep = 'Re-engage later';
    append = 'Deferred for later follow-up';
    break;
  case 'Closed':
    nextActionDate = '';
    recommendedNextStep = 'No further action';
    append = 'Lead closed';
    break;
}

const statusNotes = [currentNotes, append ? `${today}: ${append}` : ''].filter(Boolean).join(' | ');

return {
  json: {
    ...$json,
    last_contact_date: lastContactDate,
    next_action_date: nextActionDate,
    overview_sent: overviewSent,
    booked_call: bookedCall,
    call_date: callDate,
    recommended_next_step: recommendedNextStep,
    status_notes: statusNotes
  }
};

